import csv
import os
import sys

def load_mapping_file(mapping_path):
    """Load gene symbol to Ensembl ID mapping into a dictionary."""
    if not os.path.exists(mapping_path):
        raise FileNotFoundError(f"Mapping file not found: {mapping_path}")

    mapping = {}
    try:
        with open(mapping_path, mode='r', newline='', encoding='utf-8') as f:
            reader = csv.DictReader(f)
            # Validate required columns
            if reader.fieldnames is None or 'gene_symbol' not in reader.fieldnames or 'ensembl_id' not in reader.fieldnames:
                raise ValueError("Mapping file must contain 'gene_symbol' and 'ensembl_id' columns.")

            for row_num, row in enumerate(reader, start=2):
                symbol = row.get('gene_symbol', '').strip().upper()
                ensembl = row.get('ensembl_id', '').strip()
                if symbol and ensembl:
                    mapping[symbol] = ensembl
                elif symbol:
                    # Log warning for missing Ensembl ID but keep symbol for lookup
                    pass
    except csv.Error as e:
        raise ValueError(f"Malformed CSV in mapping file: {e}")

    return mapping

def load_mutation_data(db_path):
    """Load mutation data from CSV, handling malformed rows."""
    if not os.path.exists(db_path):
        raise FileNotFoundError(f"Mutation database not found: {db_path}")

    mutations = []
    try:
        with open(db_path, mode='r', newline='', encoding='utf-8') as f:
            reader = csv.DictReader(f)
            # Validate required columns
            required_cols = {'gene_symbol', 'mutation_type', 'position'}
            if reader.fieldnames is None or not required_cols.issubset(set(reader.fieldnames)):
                raise ValueError(f"Mutation file must contain columns: {required_cols}")

            for row_num, row in enumerate(reader, start=2):
                try:
                    # Normalize gene symbol for consistency
                    symbol = row.get('gene_symbol', '').strip().upper()
                    if not symbol:
                        continue # Skip rows with missing gene symbol

                    mutation_entry = {
                        'gene_symbol': symbol,
                        'mutation_type': row.get('mutation_type', '').strip(),
                        'position': row.get('position', '').strip()
                    }
                    mutations.append(mutation_entry)
                except Exception as e:
                    # Handle specific malformed row issues
                    print(f"Warning: Skipping malformed row {row_num} in {db_path}: {e}", file=sys.stderr)
                    continue
    except csv.Error as e:
        raise ValueError(f"Malformed CSV in mutation database: {e}")

    return mutations

def process_genes(gene_list, mutation_data, gene_mapping):
    """Merge gene list with mutation data and mapping."""
    results = []
    missing_genes = []

    # Create a lookup set for existing genes in mutation DB
    existing_genes = {m['gene_symbol'] for m in mutation_data}

    for gene in gene_list:
        gene_upper = gene.strip().upper()
        ensembl_id = gene_mapping.get(gene_upper)

        # Filter mutations for this gene
        gene_mutations = [m for m in mutation_data if m['gene_symbol'] == gene_upper]

        if not gene_mutations:
            if gene_upper in existing_genes:
                # Gene exists in DB but has no mutations (or data missing)
                results.append({
                    'gene_symbol': gene_upper,
                    'ensembl_id': ensembl_id,
                    'mutations': [],
                    'status': 'No mutations found'
                })
            else:
                # Gene not found in DB
                missing_genes.append(gene_upper)
                results.append({
                    'gene_symbol': gene_upper,
                    'ensembl_id': ensembl_id,
                    'mutations': [],
                    'status': 'Gene not found in database'
                })
        else:
            results.append({
                'gene_symbol': gene_upper,
                'ensembl_id': ensembl_id,
                'mutations': gene_mutations,
                'status': 'Success'
            })

    return results, missing_genes

def main():
    # Configuration
    mutation_db_path = "mutations.csv"
    mapping_file_path = "gene_mapping.csv"
    input_genes = ["TP53", "BRCA1", "UNKNOWN_GENE"]

    try:
        # 1. Load Mapping
        print("Loading gene mapping...")
        gene_mapping = load_mapping_file(mapping_file_path)

        # 2. Load Mutation Data
        print("Loading mutation database...")
        mutation_data = load_mutation_data(mutation_db_path)

        # 3. Process and Merge
        print("Processing gene list...")
        merged_results, missing_genes = process_genes(input_genes, mutation_data, gene_mapping)

        # 4. Output Results
        print("\n--- Merged Dataset Output ---")
        for item in merged_results:
            print(f"Gene: {item['gene_symbol']} | Ensembl ID: {item['ensembl_id'] or 'N/A'} | Status: {item['status']}")
            if item['mutations']:
                for mut in item['mutations']:
                    print(f"  - {mut['mutation_type']} at {mut['position']}")
            else:
                print("  - No mutations recorded")

        if missing_genes:
            print(f"\nWarning: The following genes were not found in the mutation database: {missing_genes}")

    except FileNotFoundError as e:
        print(f"Error: {e}", file=sys.stderr)
        sys.exit(1)
    except ValueError as e:
        print(f"Data Error: {e}", file=sys.stderr)
        sys.exit(1)
    except Exception as e:
        print(f"Unexpected Error: {e}", file=sys.stderr)
        sys.exit(1)

if __name__ == "__main__":
    main()
